# src/embergrave/engine/rules.py (new implementation)
# This would be the actual implementation of the new rules

class LevelSetupRule:
    def __init__(self, simulation_state):
        self.simulation_state = simulation_state

    def execute(self, action):
        # ... existing setup logic ...

        # NEW: Set ember drain multiplier based on weather
        if action.target_level.weather == "rain":
            self.simulation_state.ember_drain_multiplier = 1.5
        else:
            self.simulation_state.ember_drain_multiplier = 1.0

class EmberCollectionRule:
    def __init__(self, simulation_state):
        self.simulation_state = simulation_state

    def execute(self, action):
        # ... existing logic ...

        # NEW: Check if level is rain and halve ember value
        pickup = action.target
        delta = pickup.ember_value

        if self.simulation_state.current_level.weather == "rain":
            delta = int(delta * 0.5)  # Round down to integer

            # If the result is 0, add a fizzle effect (observable signal)
            if delta == 0 and pickup.ember_value > 0:
                # Trigger visual/audio fizzle effect
                self.simulation_state.emit_event("ember_fizzle")

        # ... continue with refund logic ...

class GlideResolutionRule:
    def __init__(self, simulation_state):
        self.simulation_state = simulation_state

    def execute(self, action):
        # ... existing logic ...

        # NEW: Apply multiplier to ember drain during glide
        if self.simulation_state.current_level.weather == "rain":
            multiplier = 1.5
        else:
            multiplier = 1.0

        # Pass this multiplier to the continuous ember drain step
        self.simulation_state.ember_drain_multiplier = multiplier

class PhysicsTickRule:
    def __init__(self, simulation_state):
        self.simulation_state = simulation_state

    def execute(self, action):
        # ... existing logic ...

        # NEW: Use multiplier in ember drain
        if self.simulation_state.moth_movement_state == "gliding":
            amount_to_drain = (1.0/60.0) * self.simulation_state.ember_drain_multiplier
            self.simulation_state.drain_ember(amount_to_drain)

